export const withoutProperties = (
  schema: OpenapiSchemaObject,
  properties: string[],
) => {
  if (!schema.properties) {
    return schema;
  }

  const newProperties = removeOptionalKeysFromObjectStrings(
    schema.properties,
    properties,
  );

  return { ...schema, properties: newProperties };
};

export const replaceRefs = (schema: OpenapiSchemaObject, refs: O) => {
  const string = JSON.stringify(schema);

  const finalString = Object.keys(refs).reduce((newString, refKey) => {
    const json = JSON.stringify(refs[refKey]);
    const jsonWithoutBrackets = json.slice(1, json.length - 1);

    // NB: no spaces!
    return newString.replaceAll(`"$ref":"${refKey}"`, jsonWithoutBrackets);
  }, string);

  // console.log(finalString);
  return JSON.parse(finalString) as any;
};

export const renameRefs = (schema: OpenapiSchemaObject | undefined) => {
  if (!schema) {
    return schema;
  }
  const string = JSON.stringify(schema);

  const newString = string.replaceAll(
    `"$ref":"#/definitions/`,
    `"$ref":"#/components/schemas/`,
  );

  return JSON.parse(newString) as any;
};

export const makeOpenapi = async (context: StandardContext) => {
  if (!context.me_personSlug || !context.host) {
    return { isSuccessful: false, message: "Please login" };
  }

  const projectRelativeLocation = [
    "memory/persons",
    context.me_personSlug,
    "files",
  ];

  const absoluteFilesPath = path.join(projectRoot, ...projectRelativeLocation);

  if (!fs.existsSync(absoluteFilesPath)) {
    return { isSuccessful: false, message: "Not found" };
  }

  const absoluteSchemaPaths = (
    await fs.readdir(absoluteFilesPath, {
      encoding: "utf8",
    })
  )
    .map((filename) =>
      path.join(absoluteFilesPath, filename, `${filename}.schema.json`),
    )
    .filter(fs.existsSync);

  const schemas = (
    await Promise.all(
      absoluteSchemaPaths.map(async (p) => {
        const schema = await readJsonFile<MainCapableJsonSchema>(p);

        const objectSchema = schema?.properties?.items?.items;
        if (!objectSchema) {
          return;
        }
        const modelKeys = Object.keys(objectSchema.properties);

        return {
          name: withoutSubExtensions(path.parse(p).base),
          schema,
          modelKeys,
          objectSchema,
        };
      }),
    )
  ).filter(notEmpty);

  // crude
  const actionSchemaCreateFunction =
    await getIndexedSwcStatement<SwcFunction>("actionSchemaCreate");

  const createSchema = actionSchemaCreateFunction?.parameters?.[0]
    ?.schema as OpenapiSchemaObject;
  const createReturnType = (actionSchemaCreateFunction?.returnType?.schema || {
    $ref: "#/components/schemas/StandardResponse",
  }) as OpenapiSchemaObject;

  const actionSchemaReadFunction =
    await getIndexedSwcStatement<SwcFunction>("actionSchemaRead");
  const readSchema = actionSchemaReadFunction?.parameters?.[0]
    ?.schema as OpenapiSchemaObject;
  const readReturnType = (actionSchemaReadFunction?.returnType?.schema || {
    $ref: "#/components/schemas/StandardResponse",
  }) as OpenapiSchemaObject;

  const actionSchemaUpdateFunction =
    await getIndexedSwcStatement<SwcFunction>("actionSchemaUpdate");
  const updateSchema = actionSchemaUpdateFunction?.parameters?.[0]
    ?.schema as OpenapiSchemaObject;
  const updateReturnType = (actionSchemaUpdateFunction?.returnType?.schema || {
    $ref: "#/components/schemas/StandardResponse",
  }) as OpenapiSchemaObject;

  const actionSchemaDeleteFunction =
    await getIndexedSwcStatement<SwcFunction>("actionSchemaDelete");
  const deleteSchema = actionSchemaDeleteFunction?.parameters?.[0]
    ?.schema as OpenapiSchemaObject;
  const deleteReturnType = (actionSchemaDeleteFunction?.returnType?.schema || {
    $ref: "#/components/schemas/StandardResponse",
  }) as OpenapiSchemaObject;

  const actionSchemaExecuteFunction = await getIndexedSwcStatement<SwcFunction>(
    "actionSchemaExecute",
  );
  const executeSchema = actionSchemaExecuteFunction?.parameters?.[0]
    ?.schema as OpenapiSchemaObject;
  const executeReturnType = (actionSchemaExecuteFunction?.returnType
    ?.schema || {
    $ref: "#/components/schemas/StandardResponse",
  }) as OpenapiSchemaObject;

  const crudeDefinitions = renameRefs({
    ...actionSchemaCreateFunction?.otherDefs,
    ...actionSchemaReadFunction?.otherDefs,
    ...actionSchemaUpdateFunction?.otherDefs,
    ...actionSchemaDeleteFunction?.otherDefs,
    ...actionSchemaExecuteFunction?.otherDefs,
  }) as any;
  const modelPaths = schemas
    .map((schema) => {
      const kebabName = schema.name;

      //Create the enum for keys for the model
      const modelKeyEnum: CapableJsonSchema = {
        type: "string",
        enum: schema.modelKeys,
      };
      //Create the ModelItemPartial
      const modelItemPartial = schema.objectSchema;
      const modelRefs = {
        "#/definitions/ModelKey": modelKeyEnum,
        "#/definitions/ModelItemPartial": modelItemPartial,
      };
      const pathsObjectPart = {
        [`/v1/${kebabName}`]: {
          post: {
            // security:[]
            summary: `Create ${schema.name}`,
            description: createSchema.description,
            operationId: `create${pascalCase(schema.name)}`,
            // Not sure how this below part works!!!
            requestBody: {
              required: true,
              content: {
                "application/json": {
                  schema: renameRefs(
                    withoutProperties(replaceRefs(createSchema, modelRefs), [
                      "projectRelativePath",
                    ]),
                  ),
                } satisfies OpenapiMediaType,
              },
            },

            responses: {
              "200": {
                description: "Standard response",
                content: {
                  "application/json": {
                    schema: renameRefs(
                      replaceRefs(createReturnType, modelRefs),
                    ),
                  },
                },
              },
            },
          },

          get: {
            summary: `Read ${schema.name}`,
            description: readSchema.description,
            operationId: `read${pascalCase(schema.name)}`,
            // Not sure how this below part works!!!
            requestBody: {
              required: true,
              content: {
                "application/json": {
                  schema: renameRefs(
                    withoutProperties(replaceRefs(readSchema, modelRefs), [
                      "projectRelativePath",
                    ]),
                  ),
                } satisfies OpenapiMediaType,
              },
            },

            responses: {
              "200": {
                description: "Standard response",
                content: {
                  "application/json": {
                    schema: renameRefs(replaceRefs(readReturnType, modelRefs)),
                  },
                },
              },
            },
          },

          patch: {
            summary: `Update ${schema.name}`,
            description: updateSchema.description,
            operationId: `update${pascalCase(schema.name)}`,
            // Not sure how this below part works!!!
            requestBody: {
              required: true,
              content: {
                "application/json": {
                  schema: renameRefs(
                    withoutProperties(replaceRefs(updateSchema, modelRefs), [
                      "projectRelativePath",
                    ]),
                  ),
                } satisfies OpenapiMediaType,
              },
            },

            responses: {
              "200": {
                description: "Standard response",
                content: {
                  "application/json": {
                    schema: renameRefs(
                      replaceRefs(updateReturnType, modelRefs),
                    ),
                  },
                },
              },
            },
          },

          delete: {
            summary: `Delete ${schema.name}`,
            description: deleteSchema.description,
            operationId: `delete${pascalCase(schema.name)}`,
            // Not sure how this below part works!!!
            requestBody: {
              required: true,
              content: {
                "application/json": {
                  schema: renameRefs(
                    withoutProperties(replaceRefs(deleteSchema, modelRefs), [
                      "projectRelativePath",
                    ]),
                  ),
                } satisfies OpenapiMediaType,
              },
            },

            responses: {
              "200": {
                description: "Standard response",
                content: {
                  "application/json": {
                    schema: renameRefs(
                      replaceRefs(deleteReturnType, modelRefs),
                    ),
                  },
                },
              },
            },
          },

          put: {
            summary: `Execute ${schema.name}`,
            description: executeSchema.description,
            operationId: `generate${pascalCase(schema.name)}`,
            requestBody: {
              required: true,

              content: {
                "application/json": {
                  schema: renameRefs(
                    withoutProperties(replaceRefs(executeSchema, modelRefs), [
                      "projectRelativePath",
                    ]),
                  ),
                } satisfies OpenapiMediaType,
              },
            },

            responses: {
              "200": {
                description: "Standard response",
                content: {
                  "application/json": {
                    schema: renameRefs(
                      replaceRefs(executeReturnType, modelRefs),
                    ),
                  },
                },
              },
            },
          },
        },
      } as OpenapiDocument["paths"];

      return pathsObjectPart;
    })
    .filter(notEmpty);

  const paths = mergeObjectsArray(modelPaths);

  const openapi: OpenapiDocument = {
    openapi: "3.1.0",
    info: {
      title: context.me_personSlug,
      version: "1",
      description: `OpenAPI for ${context.me_personSlug}`,
      contact: {},
      // license:{}
      //  termsOfService,
      summary: "This contains all schemas!",
    },

    servers: [
      {
        url: `https://${context.me_personSlug}.${context.host}`,
        description: "Production server",
      },
      {
        url: `http://${context.me_personSlug}.actionschema.localhost:42000`,
        description: "Local server",
      },
    ],

    paths,
    // NB: this ensures the bearer security must be applied everywhere
    //https://docs.readme.com/main/discuss/61ae673d092a3b000f1c0844
    //https://swagger.io/docs/specification/authentication/
    security: [{ bearerAuth: [] }],

    components: {
      // NB: this is needed to tell the user they need bearer authentication
      securitySchemes: {
        bearerAuth: {
          type: "http",
          scheme: "bearer",
          bearerFormat: "Bearer",
          description: "Your authToken should be provided",
        },
      },

      // callbacks:{test:{}},
      //       examples:{test:{}},
      //       headers:{test:{}},
      //       links:{test:{}},
      //       parameters:{test:{}},
      //       pathItems:{test:{}},
      //       requestBodies:{test:{}},
      //       responses:{test:{}},

      schemas: {
        StandardResponse: {
          type: "object",
          required: ["isSuccessful"],
          properties: {
            isSuccessful: { type: "boolean" },
            message: { type: "string" },
            priceCredit: { type: "number" },
          },
        },
        // TODO: all model schemas should go here

        ...crudeDefinitions,
      },
    },
  };
  return { isSuccessful: true, message: "Done", openapi };
};

export const calculateProjectSizes = async () => {
  const filePaths = (await get("Person")).result
    ?.map((person) =>
      path.join(projectRoot, "memory", "persons", person.slug, "files"),
    )
    .filter(fs.existsSync);

  if (!filePaths) {
    return;
  }

  const existingProjectPaths = filePaths
    .map((absolutePath) => {
      const projects = fs
        .readdirSync(absolutePath)
        .map((name) => path.join(absolutePath, name, `${name}.mdb`))
        .filter(fs.existsSync);

      return projects;
    })
    .flat();

  const calculatedProjectSizes = await Promise.all(
    (
      await Promise.all(
        existingProjectPaths.map(async (absolutePath) => {
          const db = makeActionSchemaDb(
            makeRelative(absolutePath, projectRoot),
          );

          const lastCalculationAt = db.get("lastSizeCalculatedAt");
          const lastOperationAt = db.get("lastOperationAt");

          const isUpdateNeeded =
            !!lastOperationAt &&
            (!lastCalculationAt || lastCalculationAt < lastOperationAt);

          //   console.log({
          //     absolutePath,
          //     lastOperationAt,
          //     lastCalculationAt,
          //     isUpdateNeeded,
          //   });

          if (!isUpdateNeeded) {
            // no recalculation needed
            return;
          }

          return db;
        }),
      )
    )
      .filter(notEmpty)
      .map(async (db) => {
        // calculate size
        const absoluteFolderPath = path.join(
          projectRoot,
          path.parse(db.projectRelativePath).dir,
        );

        const projectSizeBytes = await getFolderSize(absoluteFolderPath);
        console.log(`${db.projectRelativePath} size: ${projectSizeBytes}`);
        await db.put("projectSizeBytes", projectSizeBytes);
        await db.put("lastSizeCalculatedAt", Date.now());

        return { absoluteFolderPath, projectSizeBytes };
      }),
  );

  return calculateProjectSizes;
};

export const getTableItems = async (firstFileProjectRelativePath: string) => {
  const absolutePath = path.join(projectRoot, firstFileProjectRelativePath);

  const firstFileExtension = getExtension(
    firstFileProjectRelativePath,
  ).toLowerCase();

  if (firstFileExtension === "csv") {
    // csv to array
    const array = await tryParseCsv(absolutePath);
    const items = array.map((item) => {
      const newItem: { [key: string]: any } = mergeObjectsArray(
        Object.keys(item).map((key) => {
          const value = item[key];
          if (value === "") {
            return { [key]: undefined };
          }
          return { [key]: value };
        }),
      );

      return newItem;
    });

    return items as O[];
  } else if (firstFileExtension === "xls" || firstFileExtension === "xlsx") {
    // xslx to array
    return [] as O[];
  } else if (firstFileExtension === "json") {
    // json to array
    const json = await readJsonFile<Json>(absolutePath);
    const items = Array.isArray(json)
      ? json
      : typeof json === "object" &&
        json !== null &&
        json.items &&
        Array.isArray(json.items)
      ? json.items
      : undefined;
    return (items as O[]) || [];
  } else {
    return [];
  }
};

export const processUploadedFilesGridProject = async (
  context: StandardContext & {
    projectRelativePath: string;
    projectRelativeFilePaths: string[];
  },
) => {
  const { projectRelativeFilePaths, projectRelativePath, ...standardContext } =
    context;

  const canRead = isAllTrue(
    (
      await Promise.all(
        projectRelativeFilePaths.map((p) => {
          return getMdbAuthorization({
            ...standardContext,
            projectRelativePath: p,
          });
        }),
      )
    ).map((x) => x.canRead),
  );

  const { canWrite } = await getSimpleFsAuthorization({
    ...standardContext,
    projectRelativePath,
  });

  if (!canWrite || !canRead) {
    return {
      isSuccessful: false,
      message: "You are not authorized to do this",
    };
  }

  // If it's one file of type CSV, XLSX or JSON
  const firstFileExtension = projectRelativeFilePaths[0]
    ? getExtension(projectRelativeFilePaths[0]).toLowerCase()
    : undefined;

  const isGridFile =
    projectRelativeFilePaths.length === 1 &&
    firstFileExtension &&
    ["xls", "xlsx", "csv", "json"].includes(firstFileExtension);

  if (isGridFile) {
    const array = await getTableItems(projectRelativeFilePaths[0]);

    const result = await actionSchemaCreate({
      ...standardContext,
      items: array,
      projectRelativePath,
      totalPriceCredit: 0,
      shouldExecuteGridEntireRow: false,
    });

    return { isSuccessful: true, message: `Inserted ${array.length} rows` };
  } else if (
    projectRelativeFilePaths.length === 1 &&
    getTypeFromUrlOrPath(projectRelativeFilePaths[0]) === "text"
  ) {
    // things like markdown
    const absolutePath = path.join(projectRoot, projectRelativeFilePaths[0]);
    const string = fs.readFileSync(absolutePath, "utf8");
    const lines = splitTextRecursive(string, 250);

    const result = await actionSchemaCreate({
      ...standardContext,
      items: lines.map((x) => ({ item: x })),
      projectRelativePath,
      shouldExecuteGridEntireRow: false,
      totalPriceCredit: 0,
    });

    return { isSuccessful: true, message: `Inserted ${lines.length} lines` };
  } else {
    // list files as URL in JsonArray as new rows under the item column
    const items = projectRelativeFilePaths
      .map((p) => {
        if (getTypeFromUrlOrPath(p) === "text") {
          // for text we want the string of the text, no url.
          const absolutePath = path.join(projectRoot, p);
          const string = fs.readFileSync(absolutePath, "utf8");
          return { item: string };
        }
        // for any other asset we want an url to it as it's not utf8
        return { item: normalizeFileToUrl(p) };
      })
      .filter(notEmpty);

    const result = await actionSchemaCreate({
      ...standardContext,
      items,
      projectRelativePath,
      shouldExecuteGridEntireRow: false,
      totalPriceCredit: 0,
    });

    return { isSuccessful: true, message: `Inserted ${items.length} items` };
  }
};

export const copyTableIntoSpace = async (
  context: StandardContext & {
    schema?: CapableJsonSchema | null;
    json?: JsonArray;
    name?: string;
  },
) => {
  if (!context.me_personSlug || !projectRoot) {
    return { isSuccessful: false, message: "Please login" };
  }

  const { json, schema } = context;

  if (
    !json?.items ||
    typeof json !== "object" ||
    (schema && typeof schema !== "object")
  ) {
    return { isSuccessful: false, message: "Invalid input" };
  }

  // use name or "untitled"
  const realName = context.name || "untitled";

  // get the first folder available
  const firstAvailableFolderPath = getAvailableFolderPath(
    // this is the authorized location
    path.join(projectRoot, "memory/persons", context.me_personSlug, "files"),
    realName,
  );

  const absoluteDbPath = getActionSchemaDbPath(firstAvailableFolderPath);
  const projectRelativeDbPath = makeRelative(absoluteDbPath, projectRoot);

  // need to close if it was already there!
  await closeDb(projectRelativeDbPath);

  // make the folder
  await fs.mkdir(firstAvailableFolderPath, { recursive: true });

  // put all items into db
  const db = makeActionSchemaDb(projectRelativeDbPath);
  await db.insertItems(json.items);
  await db.put("status", json.status);
  await db.put("privacy", json.privacy);
  await db.put("rowGenerationStatus", json.rowGenerationStatus);

  const absoluteSchemaPath = getAbsoluteSchemaPath(projectRelativeDbPath);

  // If schema isn't given, estimate schema based on JSON
  const realSchema = schema || jsonToJsonSchema(json);
  await writeJsonToFile(absoluteSchemaPath, realSchema);

  return {
    isSuccessful: true,
    message: "Copied",
    projectRelativePath: projectRelativeDbPath,
  };
};

export const generateTypescript = async (
  context: StandardContext & { projectRelativePath: string },
) => {
  const { projectRelativePath } = context;
  const tableName = path.parse(projectRelativePath).name;

  const { schema } = await actionSchemaRead(context);
  if (!schema) {
    return { isSuccessful: false, message: "No schema" };
  }
  const tsPath = projectRelativePath.includes("memory/persons")
    ? path.join(
        projectRoot,
        path.parse(projectRelativePath).dir,
        `${tableName}.ts`,
      )
    : //  Not a person but a code schema (from admin)
      path.join(
        projectRoot,
        "packages/generated/sdk-fsorm-lmdb/src",
        `${tableName}.ts`,
      );

  const objectSchema = (schema as MainCapableJsonSchema).properties.items
    .items as CapableJsonSchema;

  // TODO: install https://www.npmjs.com/package/json-schema-to-typescript
  const tsString = await generateTypescriptFile(objectSchema, tableName);

  await fs.writeFile(tsPath, tsString, "utf8");

  return { isSuccessful: true, message: "Written" };
};

export const jsonToJsonSchema = (json: any): JSONSchema7 => {
  console.log({ json });
  const schema = toJsonSchema(json, {
    arrays: { mode: "first" },
    objects: {},
    required: false,
    strings: { detectFormat: false },
  }) as JSONSchema7;

  return { $schema: "http://json-schema.org/draft-07/schema#", ...schema };
};

export const simpleCondition = (
  context: StandardContext & {
    value: string | number | boolean;
    /** Nothing is case sensitive */
    operator?:
      | "Equal"
      | "Less than"
      | "More than"
      | "Contains"
      | "Starts with"
      | "Ends with";
    compare: string | number | boolean;
  },
) => {
  const { operator, value, compare } = context;

  if (!operator || operator === "Equal") {
    return {
      isSuccessful: true,
      result: String(value).toLowerCase() === String(compare).toLowerCase(),
    };
  }
  if (operator === "Contains") {
    return {
      isSuccessful: true,
      result: String(value)
        .toLowerCase()
        .includes(String(compare).toLowerCase()),
    };
  }

  if (operator === "Starts with") {
    return {
      isSuccessful: true,
      result: String(value)
        .toLowerCase()
        .startsWith(String(compare).toLowerCase()),
    };
  }

  if (operator === "Ends with") {
    return {
      isSuccessful: true,
      result: String(value)
        .toLowerCase()
        .endsWith(String(compare).toLowerCase()),
    };
  }

  if (operator === "Less than") {
    return { isSuccessful: true, result: value < compare };
  }
  if (operator === "More than") {
    return { isSuccessful: true, result: value > compare };
  }
  return { isSuccessful: false, message: "Unknown operator" };
};

export const findMyTables = async (context: StandardContext) => {
  const { me_personSlug } = context;

  if (!me_personSlug) {
    return { isSuccessful: false, message: "Please login" };
  }

  if (!projectRoot) {
    return { isSuccessful: false, message: "No root" };
  }

  const { result: openFiles } = await get("OpenFile", {
    personSlug: me_personSlug,
  });

  const adminTables = await findAdminTables({ ...context, openFiles });

  const projectRelativeLocation = ["memory/persons", me_personSlug, "files"];
  const absoluteFilesPath = path.join(projectRoot, ...projectRelativeLocation);

  if (!fs.existsSync(absoluteFilesPath)) {
    return { isSuccessful: false, message: "Couldn't find" };
  }

  const absolutedbFilePaths = (
    await fs.promises.readdir(absoluteFilesPath, {
      encoding: "utf8",
    })
  )
    .map((filename) =>
      path.join(absoluteFilesPath, filename, `${filename}.mdb`),
    )
    .filter(fs.existsSync);

  const tables = (
    await Promise.all(
      absolutedbFilePaths.map(async (absolutePath) => {
        if (!projectRoot) {
          return;
        }

        const folderPath = path.parse(absolutePath).dir;
        const projectFolderName = path.parse(folderPath).base;

        const projectRelativePath = makeRelative(absolutePath, projectRoot);
        const stat = await fs.promises.stat(absolutePath);
        // seems not to be always accurate. let's put it in the array json
        const createdAt = stat.birthtimeMs;

        const db = makeActionSchemaDb(projectRelativePath);

        const totalSpending = db.get("totalSpending");
        const columnSpending = db.get("columnSpending");

        const updatedAt = db.get("lastOperationAt");
        const projectSizeBytes = db.get("projectSizeBytes");
        const category = db.get("category");
        const schemaFilename = `./${path.parse(absolutePath).name}.schema.json`;
        const absoluteSchemaPath = path.join(folderPath, schemaFilename);
        const schema =
          await readJsonFile<CapableJsonSchema>(absoluteSchemaPath);

        const itemsAmount = db.getItemsAmount();

        const schemaDescription = schema?.description;
        const properties = getCapableJsonSchemaProperties(schema);

        const propertyPluginsAmount = properties
          ? sum(
              Object.values(properties).map(
                (x) => x.creationPlugins?.length || 0,
                // (x.destinationPlugins?.length || 0) +
                // (x.validationPlugins?.length || 0),
              ),
            )
          : 0;

        const pluginsAmount =
          (schema?.properties?.items?.creationPlugins?.length || 0) +
          propertyPluginsAmount;

        const isPinned = !!openFiles?.find(
          (x) =>
            x.file_projectRelativePath === projectRelativePath && x.isPinned,
        );

        const item: PublicTable = {
          isPinned,
          createdAt,
          category,
          updatedAt,
          projectRelativePath,
          schemaDescription,
          pluginsAmount,
          itemsAmount,
          projectSizeBytes,
          totalSpending,
          columnSpending,
        };
        return item;
      }),
    )
  ).filter(notEmpty);

  return {
    isSuccessful: true,
    message: "Found them",
    tables: tables.concat(adminTables || []),
  };
};

