export const getCapableJsonSchemaPluginFunctions = async (
  context: StandardContext,
) => {
  const functions = await pluginFunctions;

  // console.log(functions?.length);

  if (!functions) {
    return;
  }

  const betaMode = context.me_personSlug
    ? (await get("Person", { slug: context.me_personSlug })).result?.[0]
        ?.betaMode
    : undefined;

  const statements = await swcGet("SwcStatement");

  const swcFunctions = (
    await Promise.all(
      functions
        .filter((x) => {
          const productionStatus = x.config?.productionStatus;

          const isPluginAvailable =
            productionStatus === "alpha"
              ? betaMode === "alpha"
              : productionStatus === "beta"
              ? !!betaMode
              : true;
          return isPluginAvailable;
        })
        .map(async (x) => {
          if (!x.packageCategory || !x.packageName) {
            return;
          }

          const swcFunction = statements?.find(
            (s) =>
              s.packageCategory === x.packageCategory &&
              s.packageName === x.packageName &&
              s.name === x.name,
          ) as SwcFunction | undefined;

          return swcFunction;
        }),
    )
  ).filter(notEmpty);

  return swcFunctions;
};

