  return { isSuccessful, message: "Saved" };
};

export const getStatusDelta = async (
  context: StandardContext & { projectRelativePath?: string },
) => {
  const { me_personSlug, projectRelativePath } = context;

  if (!me_personSlug || !projectRelativePath || !projectRoot) {
    return { isSuccessful: false, message: "Please login" };
  }

  const me = (await get("Person", { slug: me_personSlug })).result?.[0];
  if (!me) {
    return { isSuccessful: false, message: "Please login..." };
  }

  // ensure we are authorized
  const authorization = await getSimpleFsAuthorization(context);

  if (!authorization.canRead) {
    return { isSuccessful: true, result: [], credit: me.credit || 0 };
  }

  // NB: Reset the data and return what it was
  const db = makeActionSchemaDb(projectRelativePath);

  const delta = db.get("delta");

  await db.put("delta", []);

  return { isSuccessful: true, result: delta, credit: me.credit || 0 };
};

export const configureGridProject = async (
  context: StandardContext & {
    projectRelativePath: string;
    name: string;
    description: string;
    privacy: "unlisted" | "public" | "private";
    category?: string;
  },
): Promise<StandardResponse & { projectRelativePath?: string }> => {
  const {
    name,
    description,
    privacy,
    projectRelativePath,
    category,
    ...standardContext
  } = context;

  const { schema, ...result } = await getSchema({
    ...standardContext,
    projectRelativePath,
  });

  if (!result.isSuccessful || !schema || !projectRoot) {
    return result;
  }

  // TODO: add once I have this in json.status
  const isBlocked = false;
  if (isBlocked) {
    return {
      isSuccessful: false,
      message: "Can't rename while operations are queued or in progress",
    };
  }

  const absoluteJsonPath = path.join(projectRoot, projectRelativePath);

  const absoluteSchemaPath = getAbsoluteSchemaPath(projectRelativePath);
  const projectRelativeSchemaPath = makeRelative(
    absoluteSchemaPath,
    projectRoot,
  );

  const absoluteOldFolderPath = path.parse(absoluteJsonPath).dir;
  const oldName = path.parse(absoluteOldFolderPath).base;

  // set description to schema
  const realName = kebabCase(name);

  const db = makeActionSchemaDb(projectRelativePath);
  await db.put("privacy", privacy);
  await db.put("category", category);

  // set privacy to json array
  await updateSingleNestedJsonFile<CapableJsonSchema>(absoluteSchemaPath, {
    description,
  });

  if (oldName === realName) {
    // no renaming required

    return {
      isSuccessful: true,
      message: "Updated your project",
    };
  }

  // NB: also rename

  const absoluteNewProjectFolderPath = path.join(
    path.parse(absoluteOldFolderPath).dir,
    realName,
  );

  if (fs.existsSync(absoluteNewProjectFolderPath)) {
    return {
      isSuccessful: false,
      message: "You already have another project with that name",
    };
  }
  // remove old json for now

  // rename the folder

  // first rename the file collection
  await renameFileCollection(projectRelativeSchemaPath, realName);
  // then rename the folder
  await fs.rename(absoluteOldFolderPath, absoluteNewProjectFolderPath);

  //rename the schema
  const relativeSchemaPath = `./${realName}.schema.json`;
  const absoluteNewJsonPath = path.join(
    absoluteNewProjectFolderPath,
    `${realName}.mdb`,
  );

  const newProjectRelativePath = makeRelative(absoluteNewJsonPath, projectRoot);

  return {
    isSuccessful: true,
    message: "Renamed",
    projectRelativePath: newProjectRelativePath,
  };
};

