export const removeSchemaColumn = async (
  context: StandardContext & { key: string; projectRelativePath: string },
) => {
  const { key, projectRelativePath, ...standardContext } = context;

  const { schema, ...result } = await getSchema({
    ...standardContext,
    projectRelativePath,
  });

  if (!result.isSuccessful || !schema || !projectRoot) {
    return result;
  }

  const properties = getCapableJsonSchemaProperties(schema);

  if (!properties || !Object.keys(properties).includes(key)) {
    return {
      isSuccessful: false,
      message: `${key} is not a column of your table`,
    };
  }
  // nice sugar
  const { [key]: removed, ...newProperties } = properties;

  const mainSchema = schema as MainCapableJsonSchema;
  const newSchema = setNestedObject(
    mainSchema,
    {
      properties: { items: { items: { properties: null } } },
    },
    newProperties,
  );

  const schemaPath = getAbsoluteSchemaPath(projectRelativePath);

  await writeJsonToFile(schemaPath, newSchema);

  //const jsonPath = path.join(projectRoot, projectRelativePath);

  const db = makeActionSchemaDb(projectRelativePath);
  await db.removeColumn(key);
  await db.resetSpending(key);

  return {
    isSuccessful: true,
    message: `Removed column`,
  };
};

export const isFirstOccurence = (
  context: StandardContext & {
    /**
     * Which column should it be the first occurence for?
     */
    columnKey: string;

    /** is provided by default*/
    row: O;
    /** should be provided by default (and overwritten by system if it was given by user). Must be secure. */
    projectRelativeGridPath: string;
  },
) => {
  const { projectRelativeGridPath, columnKey, row } = context;
  // 1) Get all values of `projectRelativeGridPath` of 0-[rowIndex] from the db
  const db = makeActionSchemaDb(projectRelativeGridPath);
  // NB: This might be inefficient if it's used on big tables, but getting just a single property does make it a bit better. If this ends up being a slowdown, it only happens when this plugin is used at least. But if we want to improve it, we could try to make this a cached thing or so. Not sure if that's easy...
  const list = db.getAllItemsForKey(columnKey);

  const firstOccurenceId = list.find((x) => {
    const isSame = x.__keyValue === row[columnKey];

    if (!isSame) {
      return false;
    }

    // Same value.
    return true;
  })?.__actionSchemaId as string | undefined;

  ///////////////////////////////////////////

  const isSameId = firstOccurenceId === row.__actionSchemaId;

  return { isSuccessful: true, result: isSameId };
};

export const setSchemaProperty = async (
  context: StandardContext & {
    key: string;
    projectRelativePath: string;
    newKeyName: string;
    capableJsonSchema: CapableJsonSchema;
  },
) => {
  const {
    key,
    projectRelativePath,
    capableJsonSchema,
    newKeyName,
    ...standardContext
  } = context;

  const { schema, ...result } = await getSchema({
    ...standardContext,
    projectRelativePath,
  });

  if (!result.isSuccessful || !schema || !projectRoot) {
    console.log({ ...standardContext, projectRelativePath }, schema, result);
    return result;
  }

  const properties = getCapableJsonSchemaProperties(schema);

  const propertyKeys = properties ? Object.keys(properties) : undefined;
  if (!properties || !propertyKeys?.includes(key)) {
    return {
      isSuccessful: false,
      message: `${key} is not a column of your table`,
    };
  }

  if (
    newKeyName !== key &&
    (propertyKeys
      .map((x) => x.toLowerCase())
      .includes(newKeyName.toLowerCase()) ||
      newKeyName === "__actionSchemaId")
  ) {
    return {
      isSuccessful: false,
      message:
        newKeyName === "__actionSchemaId"
          ? "Forbidden name"
          : `There is already a key with the name ${newKeyName}. Choose another name!`,
    };
  }

  const keyIndex = propertyKeys.findIndex((k) => k === key);
  //replace propertyName if not the same
  propertyKeys[keyIndex] = newKeyName;

  // set it in the right place!
  const newProperties = mergeObjectsArray(
    propertyKeys.map((key) => {
      if (key !== newKeyName) {
        return { [key]: properties[key] };
      }

      // only set the key if it's the new key name

      const firstCreationPlugin = capableJsonSchema.creationPlugins?.[0];

      if (firstCreationPlugin) {
        // NB: ensure to also set the propertyDependencies

        const allStringsString = firstCreationPlugin.context
          ? Object.values(firstCreationPlugin.context)
              .filter((x) => typeof x === "string")
              .map((x) => x as string)
              .join("\n")
          : "";

        const variables = findVariables(allStringsString).filter(onlyUnique2());

        firstCreationPlugin.propertyDependencies = propertyKeys.filter((key) =>
          variables.includes(key),
        );
      }

      return {
        [key]: {
          ...capableJsonSchema,
          creationPlugins: firstCreationPlugin
            ? [firstCreationPlugin]
            : undefined,
        },
      };
    }),
  );

  const mainSchema = schema as MainCapableJsonSchema;
  const newSchema = setNestedObject(
    mainSchema,
    {
      properties: { items: { items: { properties: null } } },
    },
    newProperties,
  );

  const schemaPath = getAbsoluteSchemaPath(projectRelativePath);

  await writeJsonToFile(schemaPath, newSchema);

  const db = makeActionSchemaDb(projectRelativePath);
  // rename the key too
  if (key !== newKeyName) {
    await db.renameColumn(key, newKeyName);
  }

  // Reset spending because config can be different
  await db.resetSpending(newKeyName);

  return {
    isSuccessful: true,
    message: `Updated property`,
  };
};
